     1→//! Compare crates tool
     2→
     3→use std::sync::Arc;
     4→
     5→use schemars::JsonSchema;
     6→use serde::Deserialize;
     7→use tower_mcp::{
     8→    CallToolResult, Tool, ToolBuilder,
     9→    extract::{Json, State},
    10→};
    11→
    12→use crate::state::{AppState, format_number};
    13→
    14→/// Input for comparing crates
    15→#[derive(Debug, Deserialize, JsonSchema)]
    16→pub struct CompareInput {
    17→    /// Comma-separated list of crate names to compare (2-5 crates)
    18→    crates: String,
    19→}
    20→
    21→pub fn build(state: Arc<AppState>) -> Tool {
    22→    ToolBuilder::new("compare_crates")
    23→        .title("Compare Crates")
    24→        .description(
    25→            "Compare two or more crates side by side. Returns a structured comparison of \
    26→             downloads, versions, dependencies, reverse dependencies, and freshness.",
    27→        )
    28→        .read_only()
    29→        .idempotent()
    30→        .icon("https://crates.io/assets/cargo.png")
    31→        .extractor_handler(
    32→            state,
    33→            |State(state): State<Arc<AppState>>, Json(input): Json<CompareInput>| async move {
    34→                let names: Vec<&str> = input.crates.split(',').map(|s| s.trim()).collect();
    35→
    36→                if names.len() < 2 {
    37→                    return Ok(CallToolResult::text(
    38→                        "Please provide at least 2 crate names separated by commas.",
    39→                    ));
    40→                }
    41→                if names.len() > 5 {
    42→                    return Ok(CallToolResult::text(
    43→                        "Please provide at most 5 crate names to compare.",
    44→                    ));
    45→                }
    46→
    47→                let mut output = format!("# Crate Comparison: {}\n\n", names.join(" vs "));
    48→
    49→                // Table header
    50→                output.push_str("| | ");
    51→                for name in &names {
    52→                    output.push_str(&format!("**{}** | ", name));
    53→                }
    54→                output.push('\n');
    55→
    56→                output.push_str("|---|");
    57→                for _ in &names {
    58→                    output.push_str("---|");
    59→                }
    60→                output.push('\n');
    61→
    62→                // Gather data for each crate
    63→                let mut versions_row = vec![];
    64→                let mut downloads_row = vec![];
    65→                let mut recent_row = vec![];
    66→                let mut deps_row = vec![];
    67→                let mut rev_deps_row = vec![];
    68→                let mut last_release_row = vec![];
    69→                let mut license_row = vec![];
    70→                let mut msrv_row = vec![];
    71→                let mut description_row = vec![];
    72→
    73→                for name in &names {
    74→                    let info = state.client.get_crate(name).await;
    75→                    let rev_deps = state.client.crate_reverse_dependencies(name).await;
    76→
    77→                    match info {
    78→                        Ok(resp) => {
    79→                            let c = &resp.crate_data;
    80→                            versions_row.push(c.max_version.clone());
    81→                            downloads_row.push(format_number(c.downloads));
    82→                            recent_row.push(
    83→                                c.recent_downloads
    84→                                    .map(format_number)
    85→                                    .unwrap_or_else(|| "-".to_string()),
    86→                            );
    87→                            last_release_row.push(c.updated_at.date_naive().to_string());
    88→                            description_row
    89→                                .push(c.description.clone().unwrap_or_else(|| "-".to_string()));
    90→
    91→                            // Get deps and version details from the latest version
    92→                            let version = &c.max_version;
    93→                            match state.client.crate_dependencies(name, version).await {
    94→                                Ok(deps) => {
    95→                                    let normal: Vec<_> = deps
    96→                                        .iter()
    97→                                        .filter(|d| d.kind == "normal" && !d.optional)
    98→                                        .collect();
    99→                                    deps_row.push(format!("{}", normal.len()));
   100→                                }
   101→                                Err(_) => deps_row.push("-".to_string()),
   102→                            }
   103→
   104→                            match state.client.crate_version(name, version).await {
   105→                                Ok(v) => {
   106→                                    license_row.push(v.license.unwrap_or_else(|| "-".to_string()));
   107→                                    msrv_row
   108→                                        .push(v.rust_version.unwrap_or_else(|| "-".to_string()));
   109→                                }
   110→                                Err(_) => {
   111→                                    license_row.push("-".to_string());
   112→                                    msrv_row.push("-".to_string());
   113→                                }
   114→                            }
   115→                        }
   116→                        Err(e) => {
   117→                            let err = format!("error: {}", e);
   118→                            versions_row.push(err.clone());
   119→                            downloads_row.push(err.clone());
   120→                            recent_row.push(err.clone());
   121→                            deps_row.push(err.clone());
   122→                            last_release_row.push(err.clone());
   123→                            license_row.push(err.clone());
   124→                            msrv_row.push(err.clone());
   125→                            description_row.push(err);
   126→                        }
   127→                    }
   128→
   129→                    match rev_deps {
   130→                        Ok(rd) => rev_deps_row.push(format!("{}", rd.meta.total)),
   131→                        Err(_) => rev_deps_row.push("-".to_string()),
   132→                    }
   133→                }
   134→
   135→                // Build table rows
   136→                let rows = [
   137→                    ("Description", &description_row),
   138→                    ("Latest Version", &versions_row),
   139→                    ("Total Downloads", &downloads_row),
   140→                    ("Recent Downloads", &recent_row),
   141→                    ("Direct Deps", &deps_row),
   142→                    ("Reverse Deps", &rev_deps_row),
   143→                    ("Last Release", &last_release_row),
   144→                    ("License", &license_row),
   145→                    ("MSRV", &msrv_row),
   146→                ];
   147→
   148→                for (label, values) in &rows {
   149→                    output.push_str(&format!("| {} | ", label));
   150→                    for val in *values {
   151→                        output.push_str(&format!("{} | ", val));
   152→                    }
   153→                    output.push('\n');
   154→                }
   155→
   156→                Ok(CallToolResult::text(output))
   157→            },
   158→        )
   159→        .build()
   160→}
   161→

