     1→//! Custom crates.io API client
     2→//!
     3→//! Async client for the crates.io REST API, built on reqwest with built-in
     4→//! rate limiting. Supports both anonymous and authenticated access.
     5→
     6→pub mod docsrs;
     7→pub mod error;
     8→pub mod osv;
     9→pub mod query;
    10→pub mod types;
    11→pub(crate) mod wire;
    12→
    13→mod categories;
    14→mod crates;
    15→mod keywords;
    16→mod metadata;
    17→mod owners;
    18→mod publish;
    19→mod teams;
    20→mod tokens;
    21→mod trusted;
    22→mod users;
    23→mod versions;
    24→
    25→#[cfg(test)]
    26→mod tests;
    27→
    28→use std::sync::Arc;
    29→use std::time::Duration;
    30→
    31→use serde::Serialize;
    32→use serde::de::DeserializeOwned;
    33→use tokio::sync::Mutex;
    34→use tokio::time::Instant;
    35→
    36→pub use error::Error;
    37→pub use query::{CratesQuery, CratesQueryBuilder, Sort};
    38→pub use types::*;
    39→
    40→// ── Auth ────────────────────────────────────────────────────────────────────
    41→
    42→/// Authentication credentials for the crates.io API.
    43→struct Auth {
    44→    token: String,
    45→}
    46→
    47→impl std::fmt::Debug for Auth {
    48→    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
    49→        f.debug_struct("Auth")
    50→            .field("token", &"[REDACTED]")
    51→            .finish()
    52→    }
    53→}
    54→
    55→// ── Client ──────────────────────────────────────────────────────────────────
    56→
    57→/// Async client for the crates.io REST API.
    58→///
    59→/// Includes built-in rate limiting to respect the crates.io crawling policy.
    60→/// Supports optional authentication via API token for write operations.
    61→pub struct CratesIoClient {
    62→    http: reqwest::Client,
    63→    base_url: String,
    64→    rate_limit: Duration,
    65→    last_request: Arc<Mutex<Option<Instant>>>,
    66→    auth: Option<Auth>,
    67→}
    68→
    69→impl CratesIoClient {
    70→    /// Create a new client with the given user agent and rate limit.
    71→    pub fn new(user_agent: &str, rate_limit: Duration) -> Result<Self, Error> {
    72→        Self::with_base_url(user_agent, rate_limit, "https://crates.io/api/v1")
    73→    }
    74→
    75→    /// Create a new client with a custom base URL (for testing).
    76→    pub fn with_base_url(
    77→        user_agent: &str,
    78→        rate_limit: Duration,
    79→        base_url: &str,
    80→    ) -> Result<Self, Error> {
    81→        let http = reqwest::Client::builder().user_agent(user_agent).build()?;
    82→        Ok(Self {
    83→            http,
    84→            base_url: base_url.trim_end_matches('/').to_string(),
    85→            rate_limit,
    86→            last_request: Arc::new(Mutex::new(None)),
    87→            auth: None,
    88→        })
    89→    }
    90→
    91→    /// Enable authentication with an API token.
    92→    ///
    93→    /// Returns `self` for builder-style chaining.
    94→    pub fn with_auth(mut self, token: impl Into<String>) -> Self {
    95→        self.auth = Some(Auth {
    96→            token: token.into(),
    97→        });
    98→        self
    99→    }
   100→
   101→    /// Returns the auth token or `Error::AuthRequired`.
   102→    pub(crate) fn require_auth(&self) -> Result<&str, Error> {
   103→        self.auth
   104→            .as_ref()
   105→            .map(|a| a.token.as_str())
   106→            .ok_or(Error::AuthRequired)
   107→    }
   108→
   109→    // ── Unauthenticated HTTP helpers ────────────────────────────────────
   110→
   111→    /// Enforce rate limiting between requests.
   112→    pub(crate) async fn throttle(&self) {
   113→        let mut last = self.last_request.lock().await;
   114→        if let Some(last_time) = *last {
   115→            let elapsed = last_time.elapsed();
   116→            if elapsed < self.rate_limit {
   117→                tokio::time::sleep(self.rate_limit - elapsed).await;
   118→            }
   119→        }
   120→        *last = Some(Instant::now());
   121→    }
   122→
   123→    /// Send a GET request and check the response status.
   124→    pub(crate) async fn send(&self, path: &str) -> Result<reqwest::Response, Error> {
   125→        self.throttle().await;
   126→        let url = format!("{}{}", self.base_url, path);
   127→        let resp = self.http.get(&url).send().await?;
   128→        Self::check_status(resp, path).await
   129→    }
   130→
   131→    /// Send a GET request with query parameters and check the response status.
   132→    pub(crate) async fn send_query(
   133→        &self,
   134→        path: &str,
   135→        query: &[(String, String)],
   136→    ) -> Result<reqwest::Response, Error> {
   137→        self.throttle().await;
   138→        let url = format!("{}{}", self.base_url, path);
   139→        let resp = self.http.get(&url).query(query).send().await?;
   140→        Self::check_status(resp, path).await
   141→    }
   142→
   143→    /// Map non-success HTTP status codes to typed errors.
   144→    pub(crate) async fn check_status(
   145→        resp: reqwest::Response,
   146→        path: &str,
   147→    ) -> Result<reqwest::Response, Error> {
   148→        let status = resp.status();
   149→        if status.is_success() {
   150→            Ok(resp)
   151→        } else if status == reqwest::StatusCode::NOT_FOUND {
   152→            Err(Error::NotFound(path.to_string()))
   153→        } else if status == reqwest::StatusCode::UNAUTHORIZED {
   154→            Err(Error::Unauthorized)
   155→        } else if status == reqwest::StatusCode::FORBIDDEN {
   156→            Err(Error::PermissionDenied)
   157→        } else if status == reqwest::StatusCode::TOO_MANY_REQUESTS {
   158→            Err(Error::RateLimited)
   159→        } else {
   160→            let text = resp.text().await.unwrap_or_default();
   161→            Err(Error::Api {
   162→                status: status.as_u16(),
   163→                message: text,
   164→            })
   165→        }
   166→    }
   167→
   168→    /// GET a JSON resource.
   169→    pub(crate) async fn get_json<T: DeserializeOwned>(&self, path: &str) -> Result<T, Error> {
   170→        let resp = self.send(path).await?;
   171→        Ok(resp.json().await?)
   172→    }
   173→
   174→    /// GET a JSON resource with query parameters.
   175→    pub(crate) async fn get_json_query<T: DeserializeOwned>(
   176→        &self,
   177→        path: &str,
   178→        query: &[(String, String)],
   179→    ) -> Result<T, Error> {
   180→        let resp = self.send_query(path, query).await?;
   181→        Ok(resp.json().await?)
   182→    }
   183→
   184→    /// GET a text resource (e.g. readme).
   185→    pub(crate) async fn get_text(&self, path: &str) -> Result<String, Error> {
   186→        let resp = self.send(path).await?;
   187→        Ok(resp.text().await?)
   188→    }
   189→
   190→    // ── Authenticated HTTP helpers ──────────────────────────────────────
   191→
   192→    /// Send an authenticated GET request.
   193→    pub(crate) async fn send_auth(&self, path: &str) -> Result<reqwest::Response, Error> {
   194→        let token = self.require_auth()?;
   195→        self.throttle().await;
   196→        let url = format!("{}{}", self.base_url, path);
   197→        let resp = self
   198→            .http
   199→            .get(&url)
   200→            .header("Authorization", token)
   201→            .send()
   202→            .await?;
   203→        Self::check_status(resp, path).await
   204→    }
   205→
   206→    /// Send an authenticated GET request with query parameters.
   207→    pub(crate) async fn send_query_auth(
   208→        &self,
   209→        path: &str,
   210→        query: &[(String, String)],
   211→    ) -> Result<reqwest::Response, Error> {
   212→        let token = self.require_auth()?;
   213→        self.throttle().await;
   214→        let url = format!("{}{}", self.base_url, path);
   215→        let resp = self
   216→            .http
   217→            .get(&url)
   218→            .header("Authorization", token)
   219→            .query(query)
   220→            .send()
   221→            .await?;
   222→        Self::check_status(resp, path).await
   223→    }
   224→
   225→    /// GET a JSON resource with authentication.
   226→    pub(crate) async fn get_json_auth<T: DeserializeOwned>(&self, path: &str) -> Result<T, Error> {
   227→        let resp = self.send_auth(path).await?;
   228→        Ok(resp.json().await?)
   229→    }
   230→
   231→    /// GET a JSON resource with query params and authentication.
   232→    pub(crate) async fn get_json_query_auth<T: DeserializeOwned>(
   233→        &self,
   234→        path: &str,
   235→        query: &[(String, String)],
   236→    ) -> Result<T, Error> {
   237→        let resp = self.send_query_auth(path, query).await?;
   238→        Ok(resp.json().await?)
   239→    }
   240→
   241→    /// PUT a JSON body and return a deserialized response. Requires auth.
   242→    pub(crate) async fn put_json<T: DeserializeOwned, B: Serialize>(
   243→        &self,
   244→        path: &str,
   245→        body: &B,
   246→    ) -> Result<T, Error> {
   247→        let token = self.require_auth()?;
   248→        self.throttle().await;
   249→        let url = format!("{}{}", self.base_url, path);
   250→        let resp = self
   251→            .http
   252→            .put(&url)
   253→            .header("Authorization", token)
   254→            .json(body)
   255→            .send()
   256→            .await?;
   257→        let resp = Self::check_status(resp, path).await?;
   258→        Ok(resp.json().await?)
   259→    }
   260→
   261→    /// PUT a JSON body, expecting no meaningful response body. Requires auth.
   262→    pub(crate) async fn put_json_ok<B: Serialize>(
   263→        &self,
   264→        path: &str,
   265→        body: &B,
   266→    ) -> Result<(), Error> {
   267→        let token = self.require_auth()?;
   268→        self.throttle().await;
   269→        let url = format!("{}{}", self.base_url, path);
   270→        let resp = self
   271→            .http
   272→            .put(&url)
   273→            .header("Authorization", token)
   274→            .json(body)
   275→            .send()
   276→            .await?;
   277→        Self::check_status(resp, path).await?;
   278→        Ok(())
   279→    }
   280→
   281→    /// PUT with no body, returning a deserialized JSON response. Requires auth.
   282→    pub(crate) async fn put_empty<T: DeserializeOwned>(&self, path: &str) -> Result<T, Error> {
   283→        let token = self.require_auth()?;
   284→        self.throttle().await;
   285→        let url = format!("{}{}", self.base_url, path);
   286→        let resp = self
   287→            .http
   288→            .put(&url)
   289→            .header("Authorization", token)
   290→            .send()
   291→            .await?;
   292→        let resp = Self::check_status(resp, path).await?;
   293→        Ok(resp.json().await?)
   294→    }
   295→
   296→    /// PUT with no body, returning deserialized JSON. No auth.
   297→    pub(crate) async fn put_empty_json<T: DeserializeOwned>(&self, path: &str) -> Result<T, Error> {
   298→        self.throttle().await;
   299→        let url = format!("{}{}", self.base_url, path);
   300→        let resp = self.http.put(&url).send().await?;
   301→        let resp = Self::check_status(resp, path).await?;
   302→        Ok(resp.json().await?)
   303→    }
   304→
   305→    /// DELETE and return a deserialized JSON response. Requires auth.
   306→    pub(crate) async fn delete_json<T: DeserializeOwned>(&self, path: &str) -> Result<T, Error> {
   307→        let token = self.require_auth()?;
   308→        self.throttle().await;
   309→        let url = format!("{}{}", self.base_url, path);
   310→        let resp = self
   311→            .http
   312→            .delete(&url)
   313→            .header("Authorization", token)
   314→            .send()
   315→            .await?;
   316→        let resp = Self::check_status(resp, path).await?;
   317→        Ok(resp.json().await?)
   318→    }
   319→
   320→    /// DELETE with a JSON body and return deserialized response. Requires auth.
   321→    pub(crate) async fn delete_json_with_body<T: DeserializeOwned, B: Serialize>(
   322→        &self,
   323→        path: &str,
   324→        body: &B,
   325→    ) -> Result<T, Error> {
   326→        let token = self.require_auth()?;
   327→        self.throttle().await;
   328→        let url = format!("{}{}", self.base_url, path);
   329→        let resp = self
   330→            .http
   331→            .delete(&url)
   332→            .header("Authorization", token)
   333→            .json(body)
   334→            .send()
   335→            .await?;
   336→        let resp = Self::check_status(resp, path).await?;
   337→        Ok(resp.json().await?)
   338→    }
   339→
   340→    /// DELETE expecting no response body (just check status). Requires auth.
   341→    pub(crate) async fn delete_ok(&self, path: &str) -> Result<(), Error> {
   342→        let token = self.require_auth()?;
   343→        self.throttle().await;
   344→        let url = format!("{}{}", self.base_url, path);
   345→        let resp = self
   346→            .http
   347→            .delete(&url)
   348→            .header("Authorization", token)
   349→            .send()
   350→            .await?;
   351→        Self::check_status(resp, path).await?;
   352→        Ok(())
   353→    }
   354→
   355→    /// PATCH a JSON body and return deserialized response. Requires auth.
   356→    pub(crate) async fn patch_json<T: DeserializeOwned, B: Serialize>(
   357→        &self,
   358→        path: &str,
   359→        body: &B,
   360→    ) -> Result<T, Error> {
   361→        let token = self.require_auth()?;
   362→        self.throttle().await;
   363→        let url = format!("{}{}", self.base_url, path);
   364→        let resp = self
   365→            .http
   366→            .patch(&url)
   367→            .header("Authorization", token)
   368→            .json(body)
   369→            .send()
   370→            .await?;
   371→        let resp = Self::check_status(resp, path).await?;
   372→        Ok(resp.json().await?)
   373→    }
   374→
   375→    /// POST a JSON body and return deserialized response. Requires auth.
   376→    pub(crate) async fn post_json<T: DeserializeOwned, B: Serialize>(
   377→        &self,
   378→        path: &str,
   379→        body: &B,
   380→    ) -> Result<T, Error> {
   381→        let token = self.require_auth()?;
   382→        self.throttle().await;
   383→        let url = format!("{}{}", self.base_url, path);
   384→        let resp = self
   385→            .http
   386→            .post(&url)
   387→            .header("Authorization", token)
   388→            .json(body)
   389→            .send()
   390→            .await?;
   391→        let resp = Self::check_status(resp, path).await?;
   392→        Ok(resp.json().await?)
   393→    }
   394→
   395→    /// POST a JSON body without authentication and return deserialized response.
   396→    pub(crate) async fn post_json_unauth<T: DeserializeOwned, B: Serialize>(
   397→        &self,
   398→        path: &str,
   399→        body: &B,
   400→    ) -> Result<T, Error> {
   401→        self.throttle().await;
   402→        let url = format!("{}{}", self.base_url, path);
   403→        let resp = self.http.post(&url).json(body).send().await?;
   404→        let resp = Self::check_status(resp, path).await?;
   405→        Ok(resp.json().await?)
   406→    }
   407→
   408→    /// PUT raw bytes with a custom content type and return deserialized JSON. Requires auth.
   409→    pub(crate) async fn put_bytes_json<T: DeserializeOwned>(
   410→        &self,
   411→        path: &str,
   412→        body: Vec<u8>,
   413→        content_type: &str,
   414→    ) -> Result<T, Error> {
   415→        let token = self.require_auth()?;
   416→        self.throttle().await;
   417→        let url = format!("{}{}", self.base_url, path);
   418→        let resp = self
   419→            .http
   420→            .put(&url)
   421→            .header("Authorization", token)
   422→            .header("Content-Type", content_type)
   423→            .body(body)
   424→            .send()
   425→            .await?;
   426→        let resp = Self::check_status(resp, path).await?;
   427→        Ok(resp.json().await?)
   428→    }
   429→}
