     1→//! Search crates tool
     2→
     3→use std::sync::Arc;
     4→
     5→use crate::client::{CratesQuery, Sort};
     6→use schemars::JsonSchema;
     7→use serde::Deserialize;
     8→use tower_mcp::{
     9→    CallToolResult, ResultExt, Tool, ToolBuilder,
    10→    extract::{Json, State},
    11→};
    12→
    13→use crate::state::{AppState, CrateSummary, format_number};
    14→
    15→/// Input for searching crates
    16→#[derive(Debug, Deserialize, JsonSchema)]
    17→pub struct SearchInput {
    18→    /// Search query (crate name or keywords)
    19→    query: String,
    20→    /// Sort order: relevance, downloads, recent-downloads, recent-updates, new
    21→    #[serde(default = "default_sort")]
    22→    sort: String,
    23→}
    24→
    25→fn default_sort() -> String {
    26→    "relevance".to_string()
    27→}
    28→
    29→fn parse_sort(s: &str) -> Sort {
    30→    match s {
    31→        "downloads" => Sort::Downloads,
    32→        "recent-downloads" => Sort::RecentDownloads,
    33→        "recent-updates" => Sort::RecentUpdates,
    34→        "new" => Sort::NewlyAdded,
    35→        _ => Sort::Relevance,
    36→    }
    37→}
    38→
    39→pub fn build(state: Arc<AppState>) -> Tool {
    40→    ToolBuilder::new("search_crates")
    41→        .title("Search Crates")
    42→        .description(
    43→            "Search for Rust crates on crates.io. Returns crate names, descriptions, \
    44→             download counts, and repository links.",
    45→        )
    46→        .read_only()
    47→        .idempotent()
    48→        .icon("https://crates.io/assets/cargo.png")
    49→        .extractor_handler(
    50→            state,
    51→            |State(state): State<Arc<AppState>>, Json(input): Json<SearchInput>| async move {
    52→                let sort = parse_sort(&input.sort);
    53→                let query = CratesQuery::builder()
    54→                    .search(&input.query)
    55→                    .sort(sort)
    56→                    .build();
    57→
    58→                let response = state
    59→                    .client
    60→                    .crates(query)
    61→                    .await
    62→                    .tool_context("Crates.io API error")?;
    63→
    64→                // Save search for resources
    65→                let summaries: Vec<_> = response
    66→                    .crates
    67→                    .iter()
    68→                    .map(|c| CrateSummary {
    69→                        name: c.name.clone(),
    70→                        description: c.description.clone(),
    71→                        max_version: c.max_version.clone(),
    72→                        downloads: c.downloads,
    73→                    })
    74→                    .collect();
    75→                state.save_search(input.query.clone(), summaries).await;
    76→
    77→                // Format results
    78→                let mut output = format!(
    79→                    "Found {} crates matching '{}' (showing {}):\n\n",
    80→                    response.meta.total,
    81→                    input.query,
    82→                    response.crates.len()
    83→                );
    84→
    85→                for (i, c) in response.crates.iter().enumerate() {
    86→                    output.push_str(&format!("{}. **{}** v{}\n", i + 1, c.name, c.max_version));
    87→                    if let Some(desc) = &c.description {
    88→                        output.push_str(&format!("   {}\n", desc.trim()));
    89→                    }
    90→                    output.push_str(&format!(
    91→                        "   Downloads: {} | Recent: {}\n",
    92→                        format_number(c.downloads),
    93→                        c.recent_downloads.map(format_number).unwrap_or_default()
    94→                    ));
    95→                    if let Some(repo) = &c.repository {
    96→                        output.push_str(&format!("   Repo: {}\n", repo));
    97→                    }
    98→                    output.push('\n');
    99→                }
   100→
   101→                Ok(CallToolResult::text(output))
   102→            },
   103→        )
   104→        .build()
   105→}
   106→

