     3→use std::time::Duration;
     4→
     5→use crate::client::CratesIoClient;
     6→use crate::client::docsrs::DocsRsClient;
     7→use crate::client::osv::OsvClient;
     8→use crate::docs::cache::DocsCache;
     9→use serde::{Deserialize, Serialize};
    10→use tokio::sync::RwLock;
    11→
    12→/// Summary of a crate from search results (for resource storage)
    13→#[derive(Debug, Clone, Serialize, Deserialize)]
    14→pub struct CrateSummary {
    15→    pub name: String,
    16→    pub description: Option<String>,
    17→    pub max_version: String,
    18→    pub downloads: u64,
    19→}
    20→
    21→/// Shared state for the MCP server
    22→pub struct AppState {
    23→    /// Crates.io API client (already rate-limited internally)
    24→    pub client: CratesIoClient,
    25→    /// docs.rs API client for rustdoc JSON
    26→    pub docsrs_client: DocsRsClient,
    27→    /// OSV.dev API client for vulnerability lookups
    28→    pub osv_client: OsvClient,
    29→    /// Cache for parsed rustdoc JSON
    30→    pub docs_cache: DocsCache,
    31→    /// Recent search queries (exposed as a resource)
    32→    pub recent_searches: RwLock<Vec<(String, Vec<CrateSummary>)>>,
    33→}
    34→
    35→impl AppState {
    36→    /// Create new application state
    37→    ///
    38→    /// # Arguments
    39→    /// * `rate_limit` - Minimum interval between crates.io API calls
    40→    /// * `docs_cache_max_entries` - Maximum cached rustdoc JSON entries
    41→    /// * `docs_cache_ttl` - TTL for cached rustdoc JSON entries
    42→    pub fn new(
    43→        rate_limit: Duration,
    44→        docs_cache_max_entries: usize,
    45→        docs_cache_ttl: Duration,
    46→    ) -> Result<Self, tower_mcp::BoxError> {
    47→        let user_agent = "cratesio-mcp (https://github.com/joshrotenberg/cratesio-mcp)";
    48→        let client = CratesIoClient::new(user_agent, rate_limit)
    49→            .map_err(|e| format!("Failed to create crates.io client: {e}"))?;
    50→        let docsrs_client = DocsRsClient::new(user_agent)
    51→            .map_err(|e| format!("Failed to create docs.rs client: {e}"))?;
    52→        let osv_client =
    53→            OsvClient::new(user_agent).map_err(|e| format!("Failed to create OSV client: {e}"))?;
    54→        let docs_cache = DocsCache::new(docs_cache_max_entries, docs_cache_ttl);
    55→
    56→        Ok(Self {
    57→            client,
    58→            docsrs_client,
    59→            osv_client,
    60→            docs_cache,
    61→            recent_searches: RwLock::new(Vec::new()),
    62→        })
    63→    }
    64→
    65→    /// Create application state with a custom crates.io base URL (for testing).
    66→    ///
    67→    /// Points the `CratesIoClient` at the given base URL (e.g. wiremock server)
    68→    /// with zero rate limiting for fast test execution. DocsRs/OSV clients use
    69→    /// default constructors.
    70→    pub fn with_base_url(base_url: &str) -> Result<Self, tower_mcp::BoxError> {
    71→        let user_agent = "cratesio-mcp-test";
    72→        let client = CratesIoClient::with_base_url(user_agent, Duration::from_millis(0), base_url)
    73→            .map_err(|e| format!("Failed to create crates.io client: {e}"))?;
    74→        let docsrs_client = DocsRsClient::new(user_agent)
    75→            .map_err(|e| format!("Failed to create docs.rs client: {e}"))?;
    76→        let osv_client =
    77→            OsvClient::new(user_agent).map_err(|e| format!("Failed to create OSV client: {e}"))?;
    78→        let docs_cache = DocsCache::new(10, Duration::from_secs(60));
    79→
    80→        Ok(Self {
    81→            client,
    82→            docsrs_client,
    83→            osv_client,
    84→            docs_cache,
    85→            recent_searches: RwLock::new(Vec::new()),
    86→        })
    87→    }
    88→
    89→    /// Create application state with custom base URLs for all clients (for testing).
    90→    ///
    91→    /// Points all three clients at specified base URLs with zero rate limiting.
    92→    pub fn with_all_base_urls(
    93→        crates_url: &str,
    94→        docsrs_url: &str,
    95→        osv_url: &str,
    96→    ) -> Result<Self, tower_mcp::BoxError> {
    97→        let user_agent = "cratesio-mcp-test";
    98→        let client =
    99→            CratesIoClient::with_base_url(user_agent, Duration::from_millis(0), crates_url)
   100→                .map_err(|e| format!("Failed to create crates.io client: {e}"))?;
   101→        let docsrs_client = DocsRsClient::with_base_url(user_agent, docsrs_url)
   102→            .map_err(|e| format!("Failed to create docs.rs client: {e}"))?;
   103→        let osv_client = OsvClient::with_base_url(user_agent, osv_url)
   104→            .map_err(|e| format!("Failed to create OSV client: {e}"))?;
   105→        let docs_cache = DocsCache::new(10, Duration::from_secs(60));
   106→
   107→        Ok(Self {
   108→            client,
   109→            docsrs_client,
   110→            osv_client,
   111→            docs_cache,
   112→            recent_searches: RwLock::new(Vec::new()),
   113→        })
   114→    }
   115→
   116→    /// Save a search query and its results for the recent searches resource
   117→    pub async fn save_search(&self, query: String, results: Vec<CrateSummary>) {
   118→        let mut searches = self.recent_searches.write().await;
   119→        // Keep only last 10 searches
   120→        if searches.len() >= 10 {
   121→            searches.remove(0);
   122→        }
   123→        searches.push((query, results));
   124→    }
   125→}
   126→
   127→/// Helper to format large numbers in a human-readable way
   128→pub fn format_number(n: u64) -> String {
   129→    if n >= 1_000_000 {
   130→        format!("{:.1}M", n as f64 / 1_000_000.0)
   131→    } else if n >= 1_000 {
   132→        format!("{:.1}K", n as f64 / 1_000.0)
   133→    } else {
   134→        n.to_string()
   135→    }
   136→}
   137→
   138→#[cfg(test)]
   139→mod tests {
   140→    use super::*;
   141→
   142→    #[test]
   143→    fn format_number_small() {
   144→        assert_eq!(format_number(0), "0");
   145→        assert_eq!(format_number(1), "1");
   146→        assert_eq!(format_number(999), "999");
   147→    }
   148→
   149→    #[test]
   150→    fn format_number_thousands() {
   151→        assert_eq!(format_number(1_000), "1.0K");
   152→        assert_eq!(format_number(1_500), "1.5K");
   153→        assert_eq!(format_number(999_999), "1000.0K");
   154→    }
   155→
   156→    #[test]
   157→    fn format_number_millions() {
   158→        assert_eq!(format_number(1_000_000), "1.0M");
   159→        assert_eq!(format_number(2_500_000), "2.5M");
   160→        assert_eq!(format_number(50_000_000_000), "50000.0M");
   161→    }
   162→
   163→    #[tokio::test]
   164→    async fn save_search_stores_entry() {
   165→        let state = AppState::with_base_url("http://unused").unwrap();
   166→
   167→        state
   168→            .save_search(
   169→                "tokio".to_string(),
   170→                vec![CrateSummary {
   171→                    name: "tokio".to_string(),
   172→                    description: Some("Async runtime".to_string()),
   173→                    max_version: "1.0.0".to_string(),
   174→                    downloads: 100,
   175→                }],
   176→            )
   177→            .await;
   178→
   179→        let searches = state.recent_searches.read().await;
   180→        assert_eq!(searches.len(), 1);
   181→        assert_eq!(searches[0].0, "tokio");
   182→        assert_eq!(searches[0].1[0].name, "tokio");
   183→    }
   184→
   185→    #[tokio::test]
   186→    async fn save_search_caps_at_10() {
   187→        let state = AppState::with_base_url("http://unused").unwrap();
   188→
   189→        for i in 0..12 {
   190→            state.save_search(format!("query-{i}"), Vec::new()).await;
   191→        }
   192→
   193→        let searches = state.recent_searches.read().await;
   194→        assert_eq!(searches.len(), 10);
   195→        // Oldest entries should have been evicted
   196→        assert_eq!(searches[0].0, "query-2");
   197→        assert_eq!(searches[9].0, "query-11");
   198→    }
   199→}
