    base_url: String,
    /// Base URL for fetching raw GitHub content (default: https://raw.githubusercontent.com).
    pub(crate) github_raw_base_url: String,
    rate_limit: Duration,
    last_request: Arc<Mutex<Option<Instant>>>,
    auth: Option<Auth>,
}

