pub use types::*;

// ── Auth ────────────────────────────────────────────────────────────────────

/// Authentication credentials for the crates.io API.
struct Auth {
    token: String,
}

impl std::fmt::Debug for Auth {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
