                "crate": {{
                    "name": "testcrate",
                    "updated_at": "2025-01-01T00:00:00Z",
                    "created_at": "2024-01-01T00:00:00Z",
                    "downloads": 1000,
                    "max_version": "1.0.0",
                    "max_stable_version": "1.0.0",
                    "repository": "{repo}"
                }},
                "versions": []
            }}"#
        )
    }

    const SAMPLE_CHANGELOG: &str = "\
# Changelog

## [2.0.0] - 2025-01-01
### Added
- New feature

## [1.0.0] - 2024-01-01
### Added
- Initial release
";

    #[tokio::test]
    async fn changelog_found() {
        let crates_server = MockServer::start().await;
        let github_server = MockServer::start().await;

        Mock::given(method("GET"))
            .and(path("/crates/testcrate"))
            .respond_with(
                ResponseTemplate::new(200)
                    .set_body_raw(crate_json("https://github.com/example/testcrate"), "application/json"),
            )
            .mount(&crates_server)
            .await;

        // First filename tried is CHANGELOG.md
        Mock::given(method("GET"))
            .and(path("/example/testcrate/HEAD/CHANGELOG.md"))
            .respond_with(
                ResponseTemplate::new(200).set_body_string(SAMPLE_CHANGELOG),
            )
            .mount(&github_server)
            .await;

        let state = Arc::new(
            AppState::with_changelog_urls(&crates_server.uri(), &github_server.uri()).unwrap(),
        );

        let input = ChangelogInput {
            name: "testcrate".to_string(),
